import React, { useState, useMemo } from 'react';
import './LocationAnalytics.css';

interface LocationData {
  country: string;
  city: string;
  users: number;
  percentage: number;
  flag: string;
  coordinates: [number, number];
}

interface DateRange {
  label: string;
  value: string;
  days: number;
}

const LocationAnalytics: React.FC = () => {
  const [selectedDateRange, setSelectedDateRange] = useState('7d');
  const [selectedLocation, setSelectedLocation] = useState('all');

  const dateRanges: DateRange[] = [
    { label: 'Last 7 Days', value: '7d', days: 7 },
    { label: 'Last 30 Days', value: '30d', days: 30 },
    { label: 'Last 90 Days', value: '90d', days: 90 },
    { label: 'Last Year', value: '1y', days: 365 }
  ];

  // Mock location data
  const locationData: LocationData[] = [
    { country: 'United States', city: 'New York', users: 2847, percentage: 28.5, flag: '🇺🇸', coordinates: [-74.006, 40.7128] },
    { country: 'United Kingdom', city: 'London', users: 1923, percentage: 19.2, flag: '🇬🇧', coordinates: [-0.1276, 51.5074] },
    { country: 'Germany', city: 'Berlin', users: 1456, percentage: 14.6, flag: '🇩🇪', coordinates: [13.4050, 52.5200] },
    { country: 'France', city: 'Paris', users: 1234, percentage: 12.3, flag: '🇫🇷', coordinates: [2.3522, 48.8566] },
    { country: 'Canada', city: 'Toronto', users: 987, percentage: 9.9, flag: '🇨🇦', coordinates: [-79.3832, 43.6532] },
    { country: 'Australia', city: 'Sydney', users: 756, percentage: 7.6, flag: '🇦🇺', coordinates: [151.2093, -33.8688] },
    { country: 'Japan', city: 'Tokyo', users: 543, percentage: 5.4, flag: '🇯🇵', coordinates: [139.6917, 35.6895] },
    { country: 'Brazil', city: 'São Paulo', users: 321, percentage: 3.2, flag: '🇧🇷', coordinates: [-46.6333, -23.5505] }
  ];

  const countries = ['all', ...Array.from(new Set(locationData.map(item => item.country)))];

  const filteredData = useMemo(() => {
    if (selectedLocation === 'all') {
      return locationData;
    }
    return locationData.filter(item => item.country === selectedLocation);
  }, [selectedLocation]);

  const totalUsers = filteredData.reduce((sum, item) => sum + item.users, 0);
  const topLocation = filteredData[0];

  const generateChartData = () => {
    const days = dateRanges.find(range => range.value === selectedDateRange)?.days || 7;
    const data = [];

    for (let i = days - 1; i >= 0; i--) {
      const date = new Date();
      date.setDate(date.getDate() - i);

      const baseValue = totalUsers / days;
      const variation = (Math.random() - 0.5) * 0.4;
      const value = Math.floor(baseValue * (1 + variation));

      data.push({
        date: date.toISOString().split('T')[0],
        users: value
      });
    }

    return data;
  };

  const chartData = generateChartData();
  const maxChartValue = Math.max(...chartData.map(d => d.users));

  return (
    <div className="location-analytics-container">
      <div className="location-header">
        <div className="header-left">
          <h2>Location Analytics</h2>
          <p>User distribution by geographic location</p>
        </div>

        <div className="filters">
          <div className="filter-group">
            <label>Date Range</label>
            <select 
              value={selectedDateRange} 
              onChange={(e) => setSelectedDateRange(e.target.value)}
              className="filter-select"
            >
              {dateRanges.map(range => (
                <option key={range.value} value={range.value}>
                  {range.label}
                </option>
              ))}
            </select>
          </div>

          <div className="filter-group">
            <label>Location</label>
            <select 
              value={selectedLocation} 
              onChange={(e) => setSelectedLocation(e.target.value)}
              className="filter-select"
            >
              <option value="all">All Countries</option>
              {countries.slice(1).map(country => (
                <option key={country} value={country}>
                  {country}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      <div className="analytics-grid">
        <div className="chart-section">
          <div className="chart-header">
            <h3>User Trends</h3>
            <div className="chart-stats">
              <div className="stat">
                <span className="stat-value">{totalUsers.toLocaleString()}</span>
                <span className="stat-label">Total Users</span>
              </div>
              <div className="stat">
                <span className="stat-value">+12.5%</span>
                <span className="stat-label">vs Previous Period</span>
              </div>
            </div>
          </div>

          <div className="chart-container">
            <svg className="location-chart" viewBox="0 0 600 200">
              <defs>
                <linearGradient id="locationGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                  <stop offset="0%" stopColor="#3b82f6" stopOpacity="0.3"/>
                  <stop offset="100%" stopColor="#3b82f6" stopOpacity="0.05"/>
                </linearGradient>
              </defs>

              {/* Grid lines */}
              {[0, 1, 2, 3, 4].map(i => (
                <line
                  key={i}
                  x1="0"
                  y1={i * 40}
                  x2="600"
                  y2={i * 40}
                  stroke="#e5e7eb"
                  strokeWidth="1"
                  opacity="0.5"
                />
              ))}

              {/* Chart area */}
              {chartData.length > 1 && (
                <>
                  <path
                    d={`M ${chartData.map((d, i) => 
                      `${(i / (chartData.length - 1)) * 600},${200 - (d.users / maxChartValue) * 160}`
                    ).join(' L ')}`}
                    fill="none"
                    stroke="#3b82f6"
                    strokeWidth="3"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  />

                  <path
                    d={`M ${chartData.map((d, i) => 
                      `${(i / (chartData.length - 1)) * 600},${200 - (d.users / maxChartValue) * 160}`
                    ).join(' L ')} L 600,200 L 0,200 Z`}
                    fill="url(#locationGradient)"
                  />
                </>
              )}

              {/* Data points */}
              {chartData.map((d, i) => (
                <circle
                  key={i}
                  cx={(i / (chartData.length - 1)) * 600}
                  cy={200 - (d.users / maxChartValue) * 160}
                  r="4"
                  fill="#3b82f6"
                  className="chart-point"
                />
              ))}
            </svg>
          </div>
        </div>

        <div className="locations-list">
          <div className="list-header">
            <h3>Top Locations</h3>
            <span className="location-count">{filteredData.length} locations</span>
          </div>

          <div className="locations-container">
            {filteredData.map((location, index) => (
              <div key={`${location.country}-${location.city}`} className="location-item">
                <div className="location-rank">#{index + 1}</div>

                <div className="location-info">
                  <div className="location-flag">{location.flag}</div>
                  <div className="location-details">
                    <div className="location-name">
                      <span className="city">{location.city}</span>
                      <span className="country">{location.country}</span>
                    </div>
                  </div>
                </div>

                <div className="location-stats">
                  <div className="user-count">{location.users.toLocaleString()}</div>
                  <div className="percentage">{location.percentage}%</div>
                </div>

                <div className="progress-bar">
                  <div 
                    className="progress-fill" 
                    style={{ width: `${location.percentage}%` }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="summary-cards">
        <div className="summary-card">
          <div className="card-icon">🌍</div>
          <div className="card-content">
            <div className="card-value">{countries.length - 1}</div>
            <div className="card-label">Countries</div>
          </div>
        </div>

        <div className="summary-card">
          <div className="card-icon">🏙️</div>
          <div className="card-content">
            <div className="card-value">{locationData.length}</div>
            <div className="card-label">Cities</div>
          </div>
        </div>

        <div className="summary-card">
          <div className="card-icon">👑</div>
          <div className="card-content">
            <div className="card-value">{topLocation?.city}</div>
            <div className="card-label">Top City</div>
          </div>
        </div>

        <div className="summary-card">
          <div className="card-icon">📈</div>
          <div className="card-content">
            <div className="card-value">+8.2%</div>
            <div className="card-label">Growth Rate</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LocationAnalytics;
